class Solution(object):
    def majorityFrequencyGroup(self, s):
        from collections import Counter
        freq = Counter(s)
        freq_of_freq = Counter(freq.values())
        max_count = max(freq_of_freq.values())
        # among tied modes, pick the highest frequency
        target_freq = max(f for f, c in freq_of_freq.items() if c == max_count)
        return ''.join(sorted(ch for ch, f in freq.items() if f == target_freq))
